mapper.select:
SELECT usm.sw_id , usm.sw_nm , usm.sw_expl , usm.upd_scop_cd , cd1.cd_nm cdNm1 , DECODE(usm.cust_dstrbnc_fct_yn,'Y','고객 방해 요소 있음','고객 방해 요소 없음') custDstrbncFctYn , usm.sw_intro_msg , usm.sw_inst_path , usm.hash_yn , usm.hash_algo_cd , usm.prereboot_yn , usm.postreboot_yn , usm.uiapp_yn , usm.skaf_fg_cd , usm.dvc_modl_tot_tgt_yn , usm.del_yn , usm.use_yn , usm.stm_fir_reg_date , usm.stm_fir_reg_user_id , (select count(*) from um_sw_file_dtl usfd where 1=1 and usm.sw_id = usfd.sw_id(+) and usfd.del_yn ='N' ) dvcCnt FROM um_sw_mst usm ,ad_comm_cd cd1 WHERE 1=1 AND usm.upd_scop_cd = cd1.comm_cd(+) AND cd1.comm_grp_cd = 'UPD_SCOP_CD'
AND UPPER(usm.sw_nm) like UPPER('%'||#{swNm}||'%')
AND usm.upd_scop_cd = #{updScopCd}
AND usm.use_yn = #{useYn}
AND usm.del_yn != 'Y' ORDER BY usm.stm_last_upd_date desc

SELECT usfd.sw_file_id , usm.sw_id , usfd.stb_cmcl_fg_cd , cd1.cd_nm cdNm1 , usfd.sw_file_ver , usfd.sw_file_ver as swFileVerHidden , DECODE(usfd.sw_file_dc_info,null,'N','Y') swFileDcInfoYn , usfd.sw_file_dc_info ,( SELECT depFile.SW_ID FROM UM_SW_FILE_DTL depFile WHERE depFile.SW_FILE_ID = usfd.sw_file_dc_info ) as sw_dc_info ,( SELECT depFile.SW_FILE_VER FROM UM_SW_FILE_DTL depFile WHERE depFile.SW_FILE_ID = usfd.sw_file_dc_info ) as sw_file_dc_ver ,( SELECT depSw.SW_NM FROM UM_SW_MST depSw , UM_SW_FILE_DTL depFile WHERE depSw.SW_ID = depFile.SW_ID AND depFile.SW_FILE_ID = usfd.sw_file_dc_info ) as sw_file_nm , DECODE(usfd.sw_file_local_path,null,'N','Y') swFileLocalPath , usfd.stb_ui_ver , usfd.sw_file_expl , DECODE(usfd.ecdn_lnkd_sts_cd,'02','Y','N') fileYn , usfd.file_conf_date , usfd.stm_fir_reg_date , usfd.stm_fir_reg_user_id , aum.user_nm stmFirRegUserNm , usfd.ecdn_lnkd_sts_cd , cd2.cd_nm AS ecdnLnkdStsNm , usfd.SW_FILE_FG_CD , usfd.revision FROM um_sw_mst usm , um_sw_file_dtl usfd , ad_comm_cd cd1 , ad_comm_cd cd2 , ad_user_mst aum WHERE 1=1 AND usm.sw_id = usfd.sw_id(+) AND usfd.stb_cmcl_fg_cd = cd1.comm_cd(+) AND cd1.comm_grp_cd = 'STB_CMCL_FG_CD' AND usfd.ecdn_lnkd_sts_cd = cd2.comm_cd(+) AND cd2.comm_grp_cd = 'ECDN_LNKD_STS_CD' AND usfd.stm_fir_reg_user_id = aum.user_id(+) AND usfd.del_yn != 'Y' AND usm.sw_id = #{swId}
AND usfd.stb_cmcl_fg_cd = #{stbCmclFgCd}
AND usfd.stm_fir_reg_user_id in
#{type}
AND usfd.sw_file_ver between #{minVersion} and #{maxVersion}
AND usfd.sw_file_ver = #{minVersion}
AND usfd.sw_file_ver >= #{minVersion}
AND usfd.sw_file_ver <= #{minVersion}
AND usfd.sw_file_fg_cd = #{swFileFgCd}
ORDER BY stm_fir_reg_date desc

SELECT usfd.sw_file_id , usm.sw_id , usfd.stb_cmcl_fg_cd , cd1.cd_nm cdNm1 , usfd.sw_file_ver , usfd.sw_file_ver as swFileVerHidden , DECODE(usfd.sw_file_dc_info,null,'N','Y') swFileDcInfoYn , usfd.sw_file_dc_info ,( SELECT depFile.SW_ID FROM UM_SW_FILE_DTL depFile WHERE depFile.SW_FILE_ID = usfd.sw_file_dc_info ) as sw_dc_info ,( SELECT depFile.SW_FILE_VER FROM UM_SW_FILE_DTL depFile WHERE depFile.SW_FILE_ID = usfd.sw_file_dc_info ) as sw_file_dc_ver ,( SELECT depSw.SW_NM FROM UM_SW_MST depSw , UM_SW_FILE_DTL depFile WHERE depSw.SW_ID = depFile.SW_ID AND depFile.SW_FILE_ID = usfd.sw_file_dc_info ) as sw_file_nm , DECODE(usfd.sw_file_local_path,null,'N','Y') swFileLocalPath , usfd.stb_ui_ver , usfd.sw_file_expl , DECODE(usfd.ecdn_lnkd_sts_cd,'02','Y','N') fileYn , usfd.file_conf_date , usfd.stm_fir_reg_date , usfd.stm_fir_reg_user_id , NVL(aum.user_nm, usfd.stm_fir_reg_user_id) as stmFirRegUserNm , usfd.ecdn_lnkd_sts_cd , cd2.cd_nm AS ecdnLnkdStsNm , usfd.SW_FILE_FG_CD , usfd.sw_file_nm as sw_file_dtl_nm , usfd.stb_sw_rst_ver , usfd.revision FROM um_sw_mst usm , um_sw_file_dtl usfd , ad_comm_cd cd1 , ad_comm_cd cd2 , ad_user_mst aum , ( select sw_id,sw_file_id from um_sw_file_dtl where sw_id=#{swId} and dvc_modl_tot_tgt_yn='Y' union all select f.sw_id,f.sw_file_id from um_sw_file_dtl f, um_sw_file_dvc_map m where f.sw_id=#{swId} and m.modl_cd=#{modlCd} and f.sw_id=m.sw_id and f.sw_file_id=m.sw_file_id and f.dvc_modl_tot_tgt_yn!='Y' ) usfdmap WHERE 1=1 AND usm.sw_id = usfd.sw_id(+) AND usfd.stb_cmcl_fg_cd = cd1.comm_cd(+) AND cd1.comm_grp_cd = 'STB_CMCL_FG_CD' AND usfd.ecdn_lnkd_sts_cd = #{ecdnLnkdStsCd}
AND usfd.ecdn_lnkd_sts_cd = cd2.comm_cd(+) AND cd2.comm_grp_cd = 'ECDN_LNKD_STS_CD' AND usfd.stm_fir_reg_user_id = aum.user_id(+) AND usfd.del_yn != 'Y' AND usm.sw_id = #{swId}
AND usfd.sw_id = usfdmap.sw_id AND usfd.sw_file_id = usfdmap.sw_file_id
AND usfd.stb_cmcl_fg_cd = #{stbCmclFgCd}
AND usfd.stm_fir_reg_user_id in
#{type}
AND usfd.sw_file_ver between #{minVersion} and #{maxVersion}
AND usfd.sw_file_ver = #{minVersion}
AND usfd.sw_file_ver >= #{minVersion}
AND usfd.sw_file_ver <= #{minVersion}
AND usfd.sw_file_fg_cd = #{swFileFgCd}
ORDER BY stm_fir_reg_date desc

    
    SELECT
          modl_cd
    FROM  um_sw_file_dvc_map
    WHERE sw_id = #{swId}
    AND   sw_file_id = #{swFileId}

    
    SELECT
          count(*)
    FROM  um_sw_file_dtl
    WHERE sw_file_ver = #{swFileVer}
      AND sw_id = #{swId}
      AND del_yn = 'N'

mapper.insert:
    
    INSERT INTO um_sw_mst
    (
      sw_id
    , sw_nm
    , use_yn
    , upd_scop_cd
    , sw_expl
    , cust_dstrbnc_fct_yn
    , sw_intro_msg
    , sw_inst_path
    , hash_yn
    , prereboot_yn
    , postreboot_yn
    , uiapp_yn
    , skaf_fg_cd
    , stm_fir_reg_date
    , stm_fir_reg_user_id
    )
VALUES
    (
      '2'
    , #{swNm}
    , #{useYn}
    , #{updScopCd}
    , #{swExpl}
    , #{custDstrbncFctYn}
    , #{swIntroMsg}
    , #{swInstPath}
    , #{hashYn}
    , #{prerebootYn}
    , #{postrebootYn}
    , #{uiappYn}
    , #{skafFgCd}
    , sysdate
    , #{stmFirRegUserId}
    )

