SET   sw_nm = #{swNm}
    , use_yn = #{useYn}
    , upd_scop_cd = #{updScopCd}
    , sw_expl = #{swExpl}
    , cust_dstrbnc_fct_yn = #{custDstrbncFctYn}
    , sw_intro_msg = #{swIntroMsg}
    , sw_inst_path = #{swInstPath}
    , hash_yn = #{hashYn}
    , prereboot_yn = #{prerebootYn}
    , postreboot_yn = #{postrebootYn}
    , uiapp_yn = #{uiappYn}
    , skaf_fg_cd = #{skafFgCd}
WHERE sw_id = #{swId}

